Here's the result of running `cat -n` on /workspace/YatCC/task/2/bison/par.y:
     1	/* 生成.output文件 */
     2	%verbose
     3	
     4	/* 用于调试 (yydebug) */
     5	%define parse.trace
     6	
     7	%code top {
     8	int yylex (void);             // 该函数由 Flex 生成
     9	void yyerror (char const *);	// 该函数定义在 par.cpp 中
    10	}
    11	
    12	%code requires {
    13	#include "par.hpp"
    14	#include <iostream>
    15	}
    16	
    17	%union {
    18	  std::string* RawStr;
    19	  par::Decls* Decls;
    20	  par::Exprs* Exprs;
    21	
    22	  asg::TranslationUnit* TranslationUnit;
    23	  asg::Type* Type;
    24	  asg::Expr* Expr;
    25	  asg::Decl* Decl;
    26	  asg::FunctionDecl* FunctionDecl;
    27	  asg::Stmt* Stmt;
    28	  asg::CompoundStmt* CompoundStmt;
    29	  asg::ExprStmt* ExprStmt;
    30	  asg::ReturnStmt* ReturnStmt;
    31	  asg::IfStmt* IfStmt;
    32	  asg::WhileStmt* WhileStmt;
    33	  asg::ContinueStmt* ContinueStmt;
    34	  asg::BreakStmt* BreakStmt;
    35	  asg::NullStmt* NullStmt;
    36	}
    37	
    38	/* 在下面说明每个非终结符对应的 union 成员，以便进行编译期类型检查 */
    39	%type <Type> declaration_specifiers type_specifier
    40	
    41	%type <Expr> additive_expression multiplicative_expression unary_expression postfix_expression
    42	%type <Expr> expression primary_expression assignment_expression initializer initializer_list
    43	%type <Expr> logical_or_expression logical_and_expression equality_expression relational_expression
    44	
    45	%type <Stmt> block_item statement
    46	%type <CompoundStmt> compound_statement block_item_list
    47	%type <ExprStmt> expression_statement
    48	%type <ReturnStmt> jump_statement
    49	
    50	%type <Decls> external_declaration declaration init_declarator_list parameter_list
    51	%type <Exprs> argument_expression_list
    52	%type <FunctionDecl> function_definition
    53	%type <Decl> declarator init_declarator parameter_declaration
    54	
    55	%type <TranslationUnit> translation_unit
    56	
    57	%token <RawStr> IDENTIFIER CONSTANT
    58	%token INT VOID
    59	
    60	%token RETURN
    61	
    62	%start start
    63	
    64	%%
    65	
    66	// 起始符号
    67	start
    68	  :	{
    69	      par::Symtbl::g = new par::Symtbl();
    70	    }
    71	    translation_unit
    72	    {
    73	      par::gTranslationUnit = $2;
    74	      delete par::Symtbl::g;
    75	    }
    76	  ;
    77	
    78	translation_unit
    79	  : external_declaration
    80	    {
    81	      $$ = par::gMgr.make<asg::TranslationUnit>();
    82	      for (auto&& decl: *$1)
    83	        $$->decls.push_back(decl);
    84	      delete $1;
    85	    }
    86	  | translation_unit external_declaration
    87	    {
    88	      $$ = $1;
    89	      for (auto&& decl: *$2)
    90	        $$->decls.push_back(decl);
    91	      delete $2;
    92	    }
    93	  ;
    94	
    95	external_declaration
    96	  : function_definition
    97	    {
    98	      $$ = new par::Decls();
    99	      $$->push_back($1);
   100	    }
   101	  | declaration { $$ = $1; }
   102	  ;
   103	
   104	function_definition
   105	  : declaration_specifiers declarator
   106	    {
   107	      auto funcDecl = $2->dcst<asg::FunctionDecl>();
   108	      ASSERT(funcDecl);
   109	      // 设置当前全局的函数作用变量
   110	      par::gCurrentFunction = funcDecl; 
   111	      auto ty = par::gMgr.make<asg::Type>();
   112	      if (funcDecl->type != nullptr)
   113	        ty->texp = funcDecl->type->texp; 
   114	      ty->spec = $1->spec, ty->qual = $1->qual;
   115	      funcDecl->type = ty;
   116	
   117	    }
   118	    compound_statement
   119	    {	
   120	      $$ = par::gCurrentFunction;
   121	      $$->name = $2->name;
   122	      $$->body = $4;
   123	    }
   124	  ;
   125	
   126	declaration
   127	  : declaration_specifiers init_declarator_list ';'
   128	    {
   129	      for (auto decl: *$2)
   130	      {
   131	        auto ty = par::gMgr.make<asg::Type>();
   132	        if (decl->type != nullptr)
   133	          ty->texp = decl->type->texp; // 保留前面 ArrayType 的texp
   134	        ty->spec = $1->spec, ty->qual = $1->qual;
   135	        decl->type = ty;
   136	        auto varDecl = dynamic_cast<asg::VarDecl*>(decl);
   137	        if (varDecl != nullptr)
   138	        {
   139	          if (varDecl->init != nullptr)
   140	            varDecl->init->type = decl->type;
   141	        }
   142	      }
   143	      $$ = $2;
   144	    }
   145	  ;
   146	
   147	declaration_specifiers
   148	  : type_specifier { $$ = $1; }
   149	  | type_specifier declaration_specifiers
   150	    {
   151	      $$ = $2;
   152	      $$->spec = $1->spec;
   153	    }
   154	  ;
   155	
   156	type_specifier
   157	  : VOID
   158	    {
   159	      $$ = par::gMgr.make<asg::Type>();
   160	      $$->spec = asg::Type::Spec::kVoid;
   161	    }
   162	  | INT
   163	    {
   164	      $$ = par::gMgr.make<asg::Type>();
   165	      $$->spec = asg::Type::Spec::kInt;
   166	    }
   167	  ;
   168	
   169	declarator
   170	  : IDENTIFIER
   171	    {
   172	      $$ = par::gMgr.make<asg::VarDecl>();
   173	      $$->name = std::move(*$1);
   174	      delete $1;
   175	
   176	      // 插入符号表
   177	      par::Symtbl::g->insert_or_assign($$->name, $$);
   178	    }
   179	  | declarator '[' ']' // 未知长度数组
   180	    {
   181	      $$ = $1; 
   182	      // 填充Type
   183	      auto ty = par::gMgr.make<asg::Type>();
   184	      if ($$->type != nullptr)
   185	        ty->texp=$$->type->texp;
   186	      auto p = par::gMgr.make<asg::ArrayType>();
   187	      p->len = asg::ArrayType::kUnLen;
   188	      if (ty->texp == nullptr)
   189	      {
   190	        ty->texp = p;
   191	      }
   192	      else
   193	      {
   194	        ty->texp->sub = p;
   195	      }
   196	      $$->type = ty;
   197	
   198	      // 插入符号表
   199	      par::Symtbl::g->insert_or_assign($$->name, $$);
   200	    }
   201	  | declarator '[' assignment_expression ']' // 数组定义
   202	    {
   203	      $$ = $1; 
   204	      // 填充Type
   205	      auto ty = par::gMgr.make<asg::Type>();
   206	      if ($$->type != nullptr)
   207	        ty->texp=$$->type->texp;
   208	      auto p = par::gMgr.make<asg::ArrayType>();
   209	      auto integerLiteral = $3->dcst<asg::IntegerLiteral>();
   210	      ASSERT(integerLiteral);
   211	      p->len = integerLiteral->val;
   212	      if (ty->texp == nullptr)
   213	      {
   214	        ty->texp = p;
   215	      }
   216	      else
   217	      {
   218	        ty->texp->sub = p;
   219	      }
   220	      $$->type = ty;
   221	
   222	      // 插入符号表
   223	      par::Symtbl::g->insert_or_assign($$->name, $$);
   224	    }
   225	  | declarator '(' ')'
   226	    {
   227	      $$ = par::gMgr.make<asg::FunctionDecl>();
   228	      $$->name = $1->name;
   229	      auto ty = par::gMgr.make<asg::Type>();
   230	      auto p = par::gMgr.make<asg::FunctionType>();
   231	      ty->texp = p;
   232	      $$->type = ty;
   233	
   234	      // 插入符号表
   235	      par::Symtbl::g->insert_or_assign($$->name, $$);
   236	    }
   237	  // 函数列表的定义
   238	  | declarator '(' parameter_list ')'
   239	    {
   240	      auto p = par::gMgr.make<asg::FunctionDecl>();
   241	      p->name = $1->name;
   242	      p->params = *$3;
   243	      auto ty = par::gMgr.make<asg::Type>();
   244	      auto functionType = par::gMgr.make<asg::FunctionType>();
   245	      for (auto decl: *$3)
   246	      {
   247	        functionType->params.push_back(decl->type);
   248	      }
   249	      ty->texp = functionType;
   250	      p->type = ty;
   251	      $$ = p;
   252	
   253	      // 插入符号表
   254	      par::Symtbl::g->insert_or_assign($$->name, $$);
   255	    }
   256	  ;
   257	
   258	parameter_list
   259	  : parameter_declaration
   260	    {
   261	      $$ = new par::Decls();
   262	      $$->push_back($1);
   263	    }
   264	  | parameter_list ',' parameter_declaration
   265	    {
   266	      $$ = $1;
   267	      $$->push_back($3);
   268	    }
   269	  ;
   270	
   271	parameter_declaration
   272	  : declaration_specifiers declarator
   273	    {
   274	      // 保留之前定义的 Type
   275	      auto ty = par::gMgr.make<asg::Type>();
   276	      if ($2->type != nullptr)
   277	        ty->texp = $2->type->texp;
   278	      ty->spec = $1->spec, ty->qual = $1->qual;
   279	      $2->type = ty;
   280	      $$ = $2;
   281	    }
   282	  ;
   283	
   284	compound_statement
   285	  : {$$ = par::gMgr.make<asg::CompoundStmt>();} // 代码块为空的情况
   286	  |'{' '}' { $$ = par::gMgr.make<asg::CompoundStmt>(); }
   287	  | '{'
   288	    { new par::Symtbl(); } 		// 开启新的符号表作用域
   289	    block_item_list
   290	    '}'
   291	    {
   292	      delete par::Symtbl::g; 	// 结束符号表作用域
   293	      $$ = $block_item_list;
   294	    }
   295	  ;
   296	
   297	block_item_list
   298	  : block_item
   299	    {
   300	      $$ = par::gMgr.make<asg::CompoundStmt>();
   301	      $$->subs.push_back($1);
   302	    }
   303	  | block_item_list block_item
   304	    {
   305	      $$ = $1;
   306	      $$->subs.push_back($2);
   307	    }
   308	  ;
   309	
   310	block_item
   311	  : declaration
   312	    {
   313	      auto p = par::gMgr.make<asg::DeclStmt>();
   314	      for (auto decl: *$1)
   315	        p->decls.push_back(decl);
   316	      $$ = p;
   317	    }
   318	  | statement { $$ = $1; }
   319	  ;
   320	
   321	statement
   322	  : compound_statement { $$ = $1; }
   323	  | expression_statement { $$ = $1; }
   324	  | jump_statement { $$ = $1; }
   325	  ;
   326	
   327	expression_statement
   328	  : expression ';'
   329	    {
   330	      $$ = par::gMgr.make<asg::ExprStmt>();
   331	      $$->expr = $1;
   332	    }
   333	  ;
   334	
   335	jump_statement
   336	  : RETURN ';'
   337	    {
   338	      $$ = par::gMgr.make<asg::ReturnStmt>();
   339	      $$->func = par::gCurrentFunction;
   340	    }
   341	  | RETURN expression ';'
   342	    {
   343	      $$ = par::gMgr.make<asg::ReturnStmt>();
   344	      $$->func = par::gCurrentFunction;
   345	      $$->expr = $2;
   346	    }
   347	
   348	expression
   349	  : assignment_expression { $$ = $1; }
   350	  | expression ',' assignment_expression
   351	    {
   352	      auto p = par::gMgr.make<asg::BinaryExpr>();
   353	      p->op = asg::BinaryExpr::Op::kComma;
   354	      p->lft = $1, p->rht = $3;
   355	      $$ = p;
   356	    }
   357	  ;
   358	
   359	assignment_expression
   360	  : logical_or_expression { $$ = $1; }
   361	  | unary_expression '=' assignment_expression
   362	    {
   363	      auto p = par::gMgr.make<asg::BinaryExpr>();
   364	      p->op = asg::BinaryExpr::Op::kAssign;;
   365	      p->lft = $1, p->rht = $3;
   366	      $$ = p;
   367	    }
   368	  ;
   369	
   370	logical_or_expression
   371	  : logical_and_expression { $$ = $1; }
   372	  ;
   373	
   374	logical_and_expression
   375	  : equality_expression { $$ = $1; }
   376	  ;
   377	
   378	equality_expression
   379	  : relational_expression { $$ = $1; }
   380	  ;
   381	
   382	relational_expression
   383	  : additive_expression { $$ = $1; }
   384	  ;
   385	
   386	additive_expression
   387	  : multiplicative_expression { $$ = $1;}
   388	  | additive_expression '+' multiplicative_expression
   389	    {
   390	      auto p = par::gMgr.make<asg::BinaryExpr>();
   391	      p->op = asg::BinaryExpr::Op::kAdd;
   392	      p->lft = $1, p->rht = $3;
   393	      $$ = p;
   394	    }
   395	  | additive_expression '-' multiplicative_expression
   396	    {
   397	      auto p = par::gMgr.make<asg::BinaryExpr>();
   398	      p->op = asg::BinaryExpr::Op::kSub;
   399	      p->lft = $1, p->rht = $3;
   400	      $$ = p;
   401	    }
   402	  ;
   403	
   404	multiplicative_expression
   405	  : unary_expression  { $$ = $1;}
   406	  ;
   407	
   408	unary_expression
   409	  : postfix_expression { $$ = $1;}
   410	  | '-' unary_expression
   411	    {
   412	      auto p = par::gMgr.make<asg::UnaryExpr>();
   413	      p->op = asg::UnaryExpr::Op::kNeg;
   414	      p->sub = $2;
   415	      $$ = p;
   416	    }
   417	  ;
   418	
   419	postfix_expression
   420	  : primary_expression { $$ = $1; }
   421	  ;
   422	
   423	primary_expression
   424	  : IDENTIFIER
   425	    {
   426	      // 查找符号表, 找到对应的Decl
   427	      auto decl = par::Symtbl::resolve(*$1);
   428	      ASSERT(decl);
   429	      delete $1;
   430	      auto p = par::gMgr.make<asg::DeclRefExpr>();
   431	      p->decl = decl;
   432	      $$ = p;
   433	    }
   434	  | CONSTANT
   435	    {
   436	      auto p = par::gMgr.make<asg::IntegerLiteral>();
   437	      p->val = std::stoull(*$1, nullptr, 10);
   438	      delete $1;
   439	      $$ = p;
   440	    }
   441	  ;
   442	
   443	argument_expression_list
   444	  : assignment_expression
   445	    {
   446	      $$ = new par::Exprs();
   447	      $$->push_back($1);
   448	    }
   449	  | argument_expression_list ',' assignment_expression
   450	    {
   451	      $$ = $1;
   452	      $$->push_back($3);
   453	    }
   454	  ;
   455	
   456	init_declarator_list
   457	  : init_declarator
   458	    {
   459	      $$ = new par::Decls();
   460	      $$->push_back($1);
   461	    }
   462	  | init_declarator_list ',' init_declarator
   463	    {
   464	      $$ = $1;
   465	      $$->push_back($3);
   466	    }
   467	  ;
   468	
   469	init_declarator
   470	  : declarator { $$ = $1; }
   471	  | declarator '=' initializer
   472	    {
   473	      auto varDecl = $1->dcst<asg::VarDecl>();
   474	      ASSERT(varDecl);
   475	      $3->type = varDecl->type;
   476	      varDecl->init = $3;
   477	      $$ = varDecl;
   478	    }
   479	  ;
   480	
   481	 // 初始化右值
   482	initializer
   483	  : assignment_expression
   484	    {
   485	      auto callExpr = $1->dcst<asg::CallExpr>();
   486	      if (callExpr != nullptr)
   487	      {
   488	        auto implicitCastExpr = dynamic_cast<asg::ImplicitCastExpr*>(callExpr->head);
   489	        auto declRefExpr = dynamic_cast<asg::DeclRefExpr*>(implicitCastExpr->sub);
   490	        $$ = callExpr;
   491	      }
   492	      else
   493	      {
   494	        auto p = par::gMgr.make<asg::InitListExpr>();
   495	        p->list.push_back($1);
   496	        $$ = p;
   497	      }
   498	      $$->type = $1->type;
   499	    }
   500	  | '{' initializer_list '}'
   501	    {
   502	      $$ = $2;
   503	    }
   504	  | '{' '}'
   505	    {
   506	      auto p = par::gMgr.make<asg::InitListExpr>();
   507	      $$ = p;
   508	    }
   509	  ;
   510	
   511	// 初始化列表
   512	initializer_list
   513	  : initializer
   514	    {
   515	      $$ = $1;
   516	    }
   517	  | initializer_list ',' initializer
   518	    {
   519	      auto initListExpr3 = $3->dcst<asg::InitListExpr>();
   520	      auto initListExpr1 = $1->dcst<asg::InitListExpr>();
   521	      for(auto exper: initListExpr3->list)
   522	        initListExpr1->list.push_back(exper);
   523	      $$ = initListExpr1;
   524	    }
   525	  ;
